.theme-fandomdesktop-dark {
  --theme-page-accent-mix-color: #7f4d1c;
  --theme-page-background-color--secondary: #3f2d1cee;
  --theme-page-background-color: #2f1d0cdd;
  --theme-page-text-color: #ffeddc;
  --theme-border-color: #9f8d7c;
  --theme-link-color: lightsalmon;
}
.theme-fandomdesktop-light {
  --theme-page-accent-mix-color: #efcdac;
  --theme-page-background-color--secondary: #ffeddcdd;
  --theme-page-background-color: #efddccee;
  --theme-page-text-color: #1f0d00;
  --theme-border-color: #9f8d7c;
  --theme-link-color: #BD5246;
}
html .resizable-container, .page {
  font-family: 'Alan Sans', Nunito;
  word-spacing: 2px;
}

.page__main {
  background: none;
}
.main-container {
  background: linear-gradient(var(--theme-page-accent-mix-color) 1%, var(--theme-page-background-color) 2%);
}
a {
  text-decoration: none;
  background-image: linear-gradient(to right, var(--theme-link-color), var(--theme-link-color), transparent);
  background-size: 0% 5px;
  background-repeat: no-repeat;
  background-position: left bottom;
  padding-bottom: 2px;
  transition: background-size 0.3s ease-out;
}

a:hover,
a:focus-visible {
  background-size: 100% 2px;
  text-decoration: none;
  font-weight: bold;
}

.page-content {
  text-align: justify;
  padding: 2em;
}
.page-content h1, .page-content h2, .page-content h3, .page-content h4, .page-content h5 {
  font-family: 'Faculty Glyphic', Nunito;
  text-align: center;
  font-weight: 600;
  text-shadow: 0 0 2px var(--theme-page-text-color);
}
h1 {
  font-family: 'Faculty Glyphic', Nunito;
  font-weight: 600;
  text-shadow: 0 0 0.5em var(--theme-page-text-color);
}
.theme-fandomdesktop-dark .fandom-community-header,
.theme-fandomdesktop-light .fandom-community-header {
    padding: 1em 2em;
    font-family: 'Faculty Glyphic', Nunito;
}
.ratingblock {
  Margin: 0.1em 15em;
  Item-align: center;
  Text-align: center;
}

.positiverate {
  Color: green;
  Text-shadow: lime 0 0 1em;
  Padding: 0.5px;
}

.negativerate {
  Color: red;
  Text-shadow: orange 0 0 1em;
  Padding: 0.5px;
}

.rail-module {
  background: none;
}
.cred {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: 1fr;
  grid-column-gap: 5px;
  grid-row-gap: 5px;
  text-align: left;
  border-bottom: 1px solid var(--theme-border-color);
}
.cred2 {
  padding: 15px 0;
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: 2fr;
  grid-column-gap: 5px;
  grid-row-gap: 5px;
  text-align: left;
  border-bottom: 1px solid var(--theme-border-color);
}
.bl1 { grid-area: 1 / 1 / 2 / 2; }
.bl2 { grid-area: 1 / 2 / 2 / 3; }

.bl3 { grid-area: 1 / 1 / 2 / 2; }
.bl4 { grid-area: 1 / 2 / 2 / 3; }

.global-footer, .global-footer__bottom {
	background: linear-gradient(#3f2d1cee 70%, var(--theme-page-accent-mix-color) 90%);
    font-family: 'Alan Sans';
}

.global-footer__section-header, .global-footer__bottom>div {
	color: #ffeddc;
}

.global-footer__link, .global-footer__link:active, .global-footer__link:focus, .global-footer__link:visited, .global-footer__bottom a, .global-footer__bottom a:visited {
	color: lightsalmon;
}

.global-footer__link:hover, .global-footer__bottom a:hover {
	color: lightsalmon;
}

.global-footer__bottom>div~div {
	border-top: solid 1px #ffeddc;
}
